function stripHtml(str) {
  return (str || "").replace(/<[^>]*>/g, "").trim();
}

function extractHeadingsFromMarkdown(md) {
  const lines = (md || "").split("\n").map(l => l.trim());

  let h1 = "";
  const h2 = [];

  for (const line of lines) {
    const m1 = line.match(/^#\s+(.+)$/);
    if (m1 && !h1) h1 = stripHtml(m1[1]);

    const m2 = line.match(/^##\s+(.+)$/);
    if (m2) h2.push(stripHtml(m2[1]));
  }

  return { h1, h2 };
}

// ---- INPUT SOURCES ----
const blog = $node["Writing Blog"].json.output || "";
const { h1, h2 } = extractHeadingsFromMarkdown(blog);

// helper: get H2 by index (1-based)
const H2 = (n) => h2[n - 1] || "";

// Targets (these are the headings your image-plan logic uses)
const targets = {
  hero: h1 || "",
  section_1: H2(4) || "",
  section_2: H2(8) || "",
  section_3: H2(12) || "",
  section_4: H2(16) || "",
};

// ---- WordPress media items come as INPUT to this node ----
const wpItems = $input.all().map(i => i.json);

// Helper: pick best WP URL
function wpUrl(m) {
  return (
    (m && typeof m.source_url === "string" && m.source_url) ||
    (m && m.guid && typeof m.guid.rendered === "string" && m.guid.rendered) ||
    ""
  );
}

// Helper: match media item to a target heading
function matchMediaToHeading(media, heading) {
  if (!heading) return false;

  const alt = (media.alt_text || "").trim();
  const title = (media.title && (media.title.raw || media.title.rendered) || "").trim();

  // Strong match: alt_text equals heading
  if (alt && alt === heading) return true;

  // Fallback match: title equals heading
  if (title && title === heading) return true;

  return false;
}

// Build empty structure first
const structuredImages = {
  hero: null,
  section_1: null,
  section_2: null,
  section_3: null,
  section_4: null,
};

// 1) Try to match by alt_text/title to headings
for (const media of wpItems) {
  const url = wpUrl(media);
  if (!url) continue;

  for (const key of Object.keys(structuredImages)) {
    if (structuredImages[key]) continue; // already filled
    if (matchMediaToHeading(media, targets[key])) {
      structuredImages[key] = {
        url,
        alt: targets[key] || (media.alt_text || "")
      };
    }
  }
}

// 2) Fallback by order if some are still missing (hero first, then sections)
const remainingKeys = Object.keys(structuredImages).filter(k => !structuredImages[k]);
if (remainingKeys.length > 0) {
  // take medias that weren't used yet
  const usedUrls = new Set(Object.values(structuredImages).filter(Boolean).map(x => x.url));
  const unused = wpItems
    .map(m => ({ m, url: wpUrl(m) }))
    .filter(x => x.url && !usedUrls.has(x.url));

  let idx = 0;
  for (const key of remainingKeys) {
    const pick = unused[idx++];
    if (!pick) break;

    structuredImages[key] = {
      url: pick.url,
      alt: targets[key] || (pick.m.alt_text || "")
    };
  }
}

// 3) Remove null entries
Object.keys(structuredImages).forEach(
  k => structuredImages[k] === null && delete structuredImages[k]
);

return [
  {
    json: {
      images: structuredImages
    }
  }
];

const PRIMARY_KEYWORD = items[0].json.primaryKeyword || items[0].json["Primary Keyword"] || "";
const STOP_WORDS = new Set(["עם","של","על","אל","את","ה","ו","או","גם","כי","אם","זה","זו","כך","כמו","ל","מ","ב","כ","מה","מי","אין","יש","היא","הוא","הם","הן","אני","אתה","את","אנחנו","שלכם","שלכן","שלו","שלה","יותר","פחות","מאוד","מאד","כל","עוד","רק","כדי","לפי","וכן","ללא","כולל","כוללת"]);
function normalizeHebrew(str=""){return String(str).toLowerCase().replace(/[\u0591-\u05C7]/g,"").replace(/[%_.,/#!$^&*;:{}=\-\`~()\"'?<>\\|[\]+]/g," ").replace(/\s+/g," ").trim();}
function tokenize(str=""){const n=normalizeHebrew(str);if(!n)return[];return n.split(" ").map(t=>t.trim()).filter(t=>t&&t.length>=2&&!STOP_WORDS.has(t));}
function overlapScore(a,b){if(!a.length)return 0;const s=new Set(b);let h=0;for(const t of a)if(s.has(t))h++;return h/a.length;}
function containsPhrase(h,p){if(!h||!p)return false;return normalizeHebrew(h).includes(normalizeHebrew(p));}
function isValidProductUrl(url){if(!url)return false;const has=/(\/(shop|product)\/[^/]+\/[^/]+)/i.test(url)||/\/product\/[^/]+/i.test(url);const bad=/\/(חנות|חנות-טפטים)(\/?$|\/page)/i.test(url)||/\/product-category\//i.test(url)||/\/page\/\d+/i.test(url);return has&&!bad;}
const results=(items[0].json?.data?.web||[]).map(r=>{const title=r.title||"";const desc=r.description||"";const url=r.url||"";const pos=Number(r.position||999);const pk=tokenize(PRIMARY_KEYWORD);const tt=tokenize(title);const dt=tokenize(desc);const at=tt.concat(dt);const to=overlapScore(pk,tt);const do2=overlapScore(pk,dt);const ao=overlapScore(pk,at);const pt=containsPhrase(title,PRIMARY_KEYWORD)?1:0;const pd=containsPhrase(desc,PRIMARY_KEYWORD)?1:0;const ip=isValidProductUrl(url)?1:0;const pb=Math.max(0,(20-pos)/20);const score=(to*3)+(do2*1.5)+(ao*1)+(pt*2.5)+(pd*1)+(ip*3)+(pb*0.3);return{url,title,description:desc,position:pos,isProductPage:Boolean(ip),score:Number(score.toFixed(4)),matchedTokens:pk.filter(t=>new Set(at).has(t))};});
const pp=results.filter(r=>r.isProductPage);
const sorted=pp.length>0?pp.sort((a,b)=>b.score-a.score).slice(0,15):results.sort((a,b)=>b.score-a.score).slice(0,15);
return sorted.map(x=>({json:x}));

// n8n Code node (JavaScript)
// Input: items[].json = your array objects (each has data.markdown + data.metadata)

function pickFirst(arr) {
  return Array.isArray(arr) ? arr[0] : arr;
}

function cleanText(s) {
  return (s || "")
    .replace(/\r/g, "")
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function extractTitle(md) {
  const m = md.match(/^\#\s+(.+)$/m);
  return m ? m[1].trim() : "";
}

function extractPrice(md) {
  // match: "51.00 ₪" or "35.00 ₪–65.00 ₪"
  const m = md.match(/(\d+(?:\.\d+)?)\s*₪(?:\s*–\s*(\d+(?:\.\d+)?)\s*₪)?/);
  if (!m) return { price: "", price_min: null, price_max: null };
  const min = parseFloat(m[1]);
  const max = m[2] ? parseFloat(m[2]) : min;
  return { price: m[0].replace(/\s+/g, " ").trim(), price_min: min, price_max: max };
}

function extractSku(md) {
  const m = md.match(/מק["״']?ט:\s*([A-Z0-9\-]+)/i);
  return m ? m[1].trim() : "";
}

function extractImages(md) {
  // Capture markdown images: ![alt](url)
  const urls = [];
  const re = /!\[[^\]]*\]\((https?:\/\/[^)]+)\)/g;
  let match;
  while ((match = re.exec(md)) !== null) {
    const url = match[1];
    if (url.includes("cdn.userway.org/widgetapp/images/")) continue;
    urls.push(url);
  }

  // Prefer wp-content images
  const wp = urls.filter(u => u.includes("/wp-content/uploads/"));
  const main = wp[0] || urls[0] || "";

  // Gallery = unique wp images (exclude main)
  const gallery = [...new Set(wp.filter(u => u !== main))];

  return { main_image: main, gallery_images: gallery };
}

function stripNoise(md) {
  // Remove common noise blocks roughly (keep product content)
  const patterns = [
    /!\[Spinner:[^\]]*\]\([^)]+\)\n*/g,
    /!\[\]\(https:\/\/cdn\.userway\.org\/widgetapp\/images\/[^)]+\)\n*/g,
    /^40₪.*?\[סגור\]\([^)]+\)\n*/m,
    /^\s*\[דילוג לתוכן\]\([^)]+\)\n*/m,
    /##\s+מוצרים קשורים[\s\S]*$/m,        // cut everything after related products
    /עגלת קניות[\s\S]*$/m                 // or cut everything after cart widget
  ];

  let out = md;
  for (const p of patterns) out = out.replace(p, "");
  return cleanText(out);
}

function extractWeightDimensions(md) {
  // looks like:
  // | משקל | 0.5 ק"ג |
  // | מידות | 30 × 30 × 20 סנטימטרים |
  const weight = (md.match(/\|\s*משקל\s*\|\s*([^|]+)\|/m) || [])[1]?.trim() || "";
  const dimensions = (md.match(/\|\s*מידות\s*\|\s*([^|]+)\|/m) || [])[1]?.trim() || "";
  return { weight, dimensions };
}

function extractCategories(md) {
  // Categories appear as markdown links line before H1 in your samples
  // We'll take the last link-line before the first H1.
  const idx = md.search(/^\#\s+/m);
  if (idx === -1) return [];
  const before = md.slice(0, idx);
  const linkLine = before.trim().split("\n").reverse().find(l => l.includes("](https://bloklive.com/product-category/"));
  if (!linkLine) return [];
  const cats = [];
  const re = /\[([^\]]+)\]\((https?:\/\/[^)]+product-category[^)]+)\)/g;
  let m;
  while ((m = re.exec(linkLine)) !== null) cats.push(m[1].trim());
  return cats;
}

return items.map((item) => {
  const mdRaw = item.json?.data?.markdown || "";
  const meta = item.json?.data?.metadata || {};

  const md = stripNoise(mdRaw);

  const title = extractTitle(md);
  const priceObj = extractPrice(md);
  const sku = extractSku(md);
  const imgs = extractImages(md);
  const wd = extractWeightDimensions(md);
  const categories = extractCategories(md);

  return {
    json: {
      url: meta.url || meta.ogUrl || "",
      title,
      ...priceObj,
      currency: "ILS",
      sku,
      categories,
      ...imgs,
      short_description: "", // optional: add if you decide where to slice it from md
      variations: [],        // optional: parse if needed later
      weight: wd.weight,
      dimensions: wd.dimensions,
      language: meta.language || "he-IL",
      og_title: meta["og:title"] || meta.ogTitle || "",
      og_description: meta["og:description"] || meta.ogDescription || meta.description || "",
      modified_time: meta.modifiedTime || meta["article:modified_time"] || ""
    }
  };
});

const loopItems = $items("Loops");
const products = loopItems.map(i => {
  const p = i.json;
  let url = (p.url || "").split('?')[0]; // Strip ?add-to-cart= etc
  const isValid = (/(\/(shop|product)\/[^/]+\/[^/]+)/i.test(url) || /\/product\/[^/]+/i.test(url)) && !/\/(חנות|חנות-טפטים)(\/?$|\/page)/i.test(url) && !/\/product-category\//i.test(url) && !/\/page\/\d+/i.test(url);
  if (!isValid) return null;
  const img = p.main_image || "";
  const isTiny = /150x150|100x100|50x50|favicon/i.test(img);
  const validImage = img && !isTiny ? img : "";
  return { ...p, url, imagePublicUrl: p.imagePublicUrl || validImage, main_image: validImage || p.main_image };
}).filter(Boolean);
return [{ json: { products }, pairedItem: loopItems.map((_, i) => ({ item: i })) }];

/**
 * n8n Code node (JavaScript)
 * Input: item.json.output (string) OR item.json.text (string) OR item.json (string)
 * Output: columns ready for Google Sheets mapping
 */

function pickText(item) {
  return (
    item.json.output ??
    item.json.text ??
    item.json.result ??
    (typeof item.json === 'string' ? item.json : null) ??
    ''
  );
}

function normalize(s) {
  return (s || '')
    .replace(/\r\n/g, '\n')
    .replace(/[ \t]+\n/g, '\n')
    .trim();
}

function extractSection(fullText, label) {
  // Matches: 🔹 LinkedIn: ... until next 🔹 or end
  const re = new RegExp(
    String.raw`(?:^|\n)\s*(?:🔹\s*)?${label}\s*:\s*([\s\S]*?)(?=\n\s*(?:🔹\s*)?(?:LinkedIn|Facebook|Instagram|X)\s*:|\s*$)`,
    'i'
  );
  const m = fullText.match(re);
  return normalize(m ? m[1] : '');
}

function makePreview(s, max = 120) {
  const t = normalize(s).replace(/\n+/g, ' ');
  return t.length > max ? t.slice(0, max - 1) + '…' : t;
}

const out = [];

for (const item of $input.all()) {
  const raw = normalize(pickText(item));

  const linkedin = extractSection(raw, 'LinkedIn');
  const facebook = extractSection(raw, 'Facebook');
  const instagram = extractSection(raw, 'Instagram');
  const xpost = extractSection(raw, 'X');

  out.push({
    json: {
      // These keys should match your Google Sheet columns (recommended):
      LinkedIn: linkedin,
      Facebook: facebook,
      Instagram: instagram,
      X: xpost,

      // Optional useful fields:
      LinkedIn_Preview: makePreview(linkedin),
      Facebook_Preview: makePreview(facebook),
      Instagram_Preview: makePreview(instagram),
      X_Preview: makePreview(xpost),

      // Store original text too (optional):
      Raw_Output: raw,
    },
  });
}

return out;
